#!/usr/bin/env node
'use strict';

// GENERATED by the GroundWork docs-site generator — do not hand-edit. Regenerated
// verbatim on `npx groundwork-method update` (Family: docs-site — regenerate with
// recorded options).
//
// user-legibility plan, Wave 3, slice C1 — "the docsite becomes the live window".
//
// Materializes in-flight bets (worktrees + branch-only bet branches) into
// `docs/bets/_live/<slug>/` — a gitignored folder INSIDE the tree
// `source.config.ts`'s `defineDocs({ dir: '../../docs' })` already watches, so the
// stock fumadocs-mdx pipeline picks the content up with zero pipeline changes
// (D-S6). No second collection, no route-time git reads: this script runs once
// before the dev/build server starts (a "pre-render sync"), and its output is
// ordinary files on disk by the time Next/fumadocs compiles.
//
// Sources (mirrors lib/bet-status/index.js's enumeration — NOT imported, because
// this file ships standalone into user projects and must not depend on the
// groundwork-method package internals):
//   - Delivered bets:      docs/bets/_archive/ in this checkout — already watched,
//                          nothing to do here.
//   - Worktree bets:       `git worktree list --porcelain`, read each worktree's
//                          docs/bets/<slug>/ directly off disk (live).
//   - Branch-only bets:    `git for-each-ref refs/heads/bet/*` minus branches
//                          already covered by a worktree or this checkout,
//                          materialized via `git show <branch>:docs/bets/<slug>/...`.
//
// Every run is a FULL REGENERATE of docs/bets/_live/: the folder is deleted and
// rebuilt from scratch, so a bet whose worktree disappeared demotes to
// branch-only (or drops entirely if its branch is also gone) without leaving
// stale content behind — mirroring the status page's whole-regeneration
// discipline (lib/bet-status/index.js `writeStatusPage`: "never patched").
//
// Dependency-free: Node built-ins only (fs, path, child_process). No git, no
// worktrees, no bet branches -> writes nothing and exits 0 (graceful
// degradation) - a docsite with no bets in flight is not an error.

const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

// This script lives at <service>/scripts/sync-live-bets.js. The repo root is two
// levels up from the service directory — the same relative position
// source.config.ts's `dir: '../../docs'` resolves from the service directory.
const SERVICE_DIR = path.resolve(__dirname, '..');
const REPO_ROOT = path.resolve(SERVICE_DIR, '..', '..');
const DOCS_DIR = path.join(REPO_ROOT, 'docs');
const LIVE_DIR = path.join(DOCS_DIR, 'bets', '_live');

// ─── git helpers (fail-soft: missing git / not-a-repo degrades to no bets) ──

function git(args) {
  try {
    return execFileSync('git', args, {
      cwd: REPO_ROOT,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
    }).trim();
  } catch {
    return null;
  }
}

function gitLines(args) {
  const out = git(args);
  return out ? out.split('\n').filter(Boolean) : [];
}

function showAtRef(ref, relPath) {
  try {
    return execFileSync('git', ['show', `${ref}:${relPath}`], {
      cwd: REPO_ROOT,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
    });
  } catch {
    return null;
  }
}

// ─── small readers ───────────────────────────────────────────────────────────

function readFileSafe(file) {
  try {
    return fs.readFileSync(file, 'utf8');
  } catch {
    return null;
  }
}

function listDirSafe(dir) {
  try {
    return fs.readdirSync(dir, { withFileTypes: true });
  } catch {
    return [];
  }
}

// Pull the pitch's one-line goal (Solution, falling back to Problem) and title,
// for the badge line — mirrors lib/bet-status/index.js parsePitchText, kept
// deliberately small here (this script has no dependency on that module).
function parsePitchGoal(text) {
  if (text == null) return null;
  const solutionMatch = /\*\*Solution:\*\*\s*(.+)/.exec(text);
  const problemMatch = /\*\*Problem:\*\*\s*(.+)/.exec(text);
  const titleMatch = /^#\s*Bet:\s*(.+)$/m.exec(text);
  return (
    (solutionMatch && solutionMatch[1].trim()) ||
    (problemMatch && problemMatch[1].trim()) ||
    (titleMatch && titleMatch[1].trim()) ||
    null
  );
}

// ─── enumeration (mirrors lib/bet-status/index.js — not imported) ──────────

// Slugs already covered by THIS checkout's docs/bets/ (excluding _archive and
// _live itself) — these are already inside the watched tree unmodified, so the
// sync must not duplicate them into _live/.
function checkoutSlugs() {
  const dir = path.join(DOCS_DIR, 'bets');
  return new Set(
    listDirSafe(dir)
      .filter((e) => e.isDirectory() && e.name !== '_archive' && e.name !== '_live')
      .map((e) => e.name),
  );
}

function currentBranch() {
  return git(['rev-parse', '--abbrev-ref', 'HEAD']);
}

// In flight, other worktrees: read each worktree's docs/bets/<slug>/ directly off
// disk. Skips the current checkout's own worktree entry and any slug already
// covered (dedup).
function collectWorktreeBets(skipSlugs) {
  const out = git(['worktree', 'list', '--porcelain']);
  if (out == null) return { bets: [], coveredBranches: new Set() };
  const bets = [];
  const coveredBranches = new Set();
  const blocks = out.split(/\n\n+/);
  for (const block of blocks) {
    const wtMatch = /^worktree\s+(.+)$/m.exec(block);
    const branchMatch = /^branch\s+refs\/heads\/(.+)$/m.exec(block);
    if (!wtMatch) continue;
    const wtPath = wtMatch[1].trim();
    if (path.resolve(wtPath) === path.resolve(REPO_ROOT)) continue; // current checkout
    const branch = branchMatch ? branchMatch[1].trim() : null;
    if (branch) coveredBranches.add(branch);
    const betsDir = path.join(wtPath, 'docs', 'bets');
    for (const e of listDirSafe(betsDir)) {
      if (!e.isDirectory() || e.name === '_archive' || e.name === '_live') continue;
      if (skipSlugs.has(e.name)) continue;
      const pitchPath = path.join(betsDir, e.name, 'pitch.md');
      const pitchText = readFileSafe(pitchPath);
      if (pitchText == null) continue; // not a real bet dir without a pitch
      bets.push({
        slug: e.name,
        branch: branch || '(detached worktree)',
        freshness: 'live',
        sourceDir: path.join(betsDir, e.name),
        goal: parsePitchGoal(pitchText) || e.name,
      });
    }
  }
  return { bets, coveredBranches };
}

// In flight, branch-only: `git for-each-ref refs/heads/bet/*` minus branches
// already covered by a worktree or the current checkout. Materializes via
// `git show <branch>:docs/bets/<slug>/...` — every file tracked at that ref
// under the bet's directory, not just pitch.md, so the docsite renders the same
// tree a worktree would show.
function collectBranchOnlyBets(coveredBranches, skipSlugs) {
  const refs = gitLines(['for-each-ref', 'refs/heads/bet/*', '--format=%(refname:short)']);
  const bets = [];
  for (const branch of refs) {
    if (coveredBranches.has(branch)) continue;
    const slug = branch.replace(/^bet\//, '').split('/')[0];
    if (!slug || skipSlugs.has(slug)) continue;
    const pitchText = showAtRef(branch, `docs/bets/${slug}/pitch.md`);
    if (pitchText == null) continue;
    // Every file git tracks under docs/bets/<slug>/ at that ref, materialized
    // via `git show` per-file (git has no "extract subtree to disk" primitive
    // that doesn't touch the index/worktree, so this stays index-free).
    const files = gitLines(['ls-tree', '-r', '--name-only', branch, `docs/bets/${slug}/`]);
    bets.push({
      slug,
      branch,
      freshness: 'as of last commit',
      goal: parsePitchGoal(pitchText) || slug,
      materialize: (destDir) => {
        for (const relPath of files) {
          const content = showAtRef(branch, relPath);
          if (content == null) continue;
          const relInBet = path.relative(`docs/bets/${slug}`, relPath);
          const destPath = path.join(destDir, relInBet);
          fs.mkdirSync(path.dirname(destPath), { recursive: true });
          fs.writeFileSync(destPath, content);
        }
      },
    });
  }
  return bets;
}

// ─── frontmatter / badge shape ──────────────────────────────────────────────
//
// source.config.ts's schema accepts title (optional, falls back to the first
// H1), description, icon, full — no badge-specific field. The badge line rides
// `description:` frontmatter on the bet's pitch.md ONLY WHEN it doesn't already
// carry one (never clobber authored frontmatter) — the sidebar/page subtitle
// then reads "In flight — <branch>, live" / "In flight — <branch>, as of last
// commit" instead of the bet's own description. Grouping/ordering rides
// docs/bets/_live/meta.json, a sibling to docs/bets/meta.json's own convention.

function badgeLine(bet) {
  return `In flight — branch \`${bet.branch}\`, ${bet.freshness}.`;
}

// Inject/refresh the description frontmatter on a materialized pitch.md without
// disturbing the rest of the document (frontmatter is optional per
// source.config.ts, so both "no frontmatter yet" and "already has one" are
// handled).
function applyBadgeFrontmatter(pitchPath, bet) {
  const text = readFileSafe(pitchPath);
  if (text == null) return;
  const badge = badgeLine(bet);
  if (text.startsWith('---\n')) {
    const end = text.indexOf('\n---', 4);
    if (end !== -1) {
      const front = text.slice(4, end);
      const rest = text.slice(end + 4);
      const hasDescription = /(^|\n)description:/.test(front);
      const newFront = hasDescription
        ? front.replace(/(^|\n)description:.*/, `$1description: ${JSON.stringify(badge)}`)
        : `${front}\ndescription: ${JSON.stringify(badge)}`;
      fs.writeFileSync(pitchPath, `---\n${newFront}\n---${rest}`);
      return;
    }
  }
  // No frontmatter block yet — add one carrying only the badge.
  fs.writeFileSync(pitchPath, `---\ndescription: ${JSON.stringify(badge)}\n---\n\n${text}`);
}

// ─── sync = full regenerate of docs/bets/_live/ ────────────────────────────

function sync() {
  // No repo at all (no .git) -> nothing to do, exit 0.
  if (git(['rev-parse', '--git-dir']) == null) {
    return { wrote: 0, reason: 'not a git repository' };
  }

  // Full regenerate: delete and rebuild, so a vanished worktree/branch leaves
  // no stale content — the only stale-content risk otherwise (D-S6 acceptance:
  // deleting a worktree demotes to branch-only WITHOUT error, and a fully
  // vanished source's content must not survive).
  fs.rmSync(LIVE_DIR, { recursive: true, force: true });

  const skip = checkoutSlugs();
  const branch = currentBranch();
  const { bets: worktreeBets, coveredBranches } = collectWorktreeBets(skip);
  if (branch) coveredBranches.add(branch);

  const knownSlugs = new Set([...skip, ...worktreeBets.map((b) => b.slug)]);
  const branchOnlyBets = collectBranchOnlyBets(coveredBranches, knownSlugs);

  const allLive = [...worktreeBets, ...branchOnlyBets];
  if (allLive.length === 0) {
    return { wrote: 0, reason: 'no in-flight worktree or branch-only bets' };
  }

  fs.mkdirSync(LIVE_DIR, { recursive: true });

  const metaEntries = [];
  for (const bet of allLive) {
    const destDir = path.join(LIVE_DIR, bet.slug);
    fs.mkdirSync(destDir, { recursive: true });

    if (bet.sourceDir) {
      // Worktree bet: copy the live directory as-is (fs.cpSync — Node 16.7+).
      fs.cpSync(bet.sourceDir, destDir, { recursive: true });
    } else if (bet.materialize) {
      // Branch-only bet: materialize every tracked file via `git show`.
      bet.materialize(destDir);
    }

    const pitchPath = path.join(destDir, 'pitch.md');
    if (fs.existsSync(pitchPath)) applyBadgeFrontmatter(pitchPath, bet);

    metaEntries.push({ slug: bet.slug, branch: bet.branch, freshness: bet.freshness, goal: bet.goal });
  }

  // _live/meta.json: sidebar grouping for the materialized set, in the same
  // declarative-meta convention docs/bets/meta.json and generator.ts's
  // seedDocsMeta already use — read by a project's own docs/bets/meta.json if
  // it chooses to reference `_live` in its `pages` ordering (not required: the
  // stock `...` expansion already surfaces it as a normal subfolder).
  const meta = {
    generatedAt: new Date().toISOString(),
    bets: metaEntries,
  };
  fs.writeFileSync(path.join(LIVE_DIR, 'meta.json'), JSON.stringify(meta, null, 2) + '\n');

  return { wrote: allLive.length, reason: null };
}

if (require.main === module) {
  const result = sync();
  if (result.wrote > 0) {
    console.log(`[sync-live-bets] materialized ${result.wrote} in-flight bet(s) into docs/bets/_live/`);
  } else {
    console.log(`[sync-live-bets] nothing to sync (${result.reason})`);
  }
}

module.exports = { sync, LIVE_DIR };
